package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonTest {

  @Test
  public void testNewBuilder() {
    Gson gson = new Gson();
    GsonBuilder builder = gson.newBuilder();
    assertNotNull(builder);

    try {
      Field field = null;
      Class<?> clazz = builder.getClass();

      // Try to find a field of type Gson in builder's declared fields or superclass fields
      while (clazz != null) {
        for (Field f : clazz.getDeclaredFields()) {
          if (f.getType() == Gson.class) {
            field = f;
            break;
          }
        }
        if (field != null) break;
        clazz = clazz.getSuperclass();
      }

      assertNotNull(field, "Field of type Gson not found in GsonBuilder class hierarchy");
      field.setAccessible(true);
      Gson innerGson = (Gson) field.get(builder);
      assertSame(gson, innerGson);
    } catch (IllegalAccessException e) {
      fail("Reflection failed: " + e.getMessage());
    }
  }
}
